package com.yottastudios.ns.collabspace.spaceannouncement.manager.impl;

import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import com.baomidou.mybatisplus.core.conditions.update.LambdaUpdateWrapper;
import com.yottastudios.ns.collabspace.spaceannouncement.entity.SpaceAnnouncementEntity;
import com.yottastudios.ns.collabspace.spaceannouncement.enums.AnnouncementCategory;
import com.yottastudios.ns.collabspace.spaceannouncement.enums.SpaceAnnouncementStatus;
import com.yottastudios.ns.collabspace.spaceannouncement.manager.SpaceAnnouncementManager;
import com.yottastudios.ns.collabspace.spaceannouncement.mapper.SpaceAnnouncementMapper;
import jakarta.annotation.Resource;
import org.springframework.stereotype.Service;

import java.time.LocalDateTime;
import java.util.List;

@Service
public class SpaceAnnouncementManagerImpl implements SpaceAnnouncementManager {

    @Resource
    private SpaceAnnouncementMapper spaceAnnouncementMapper;

    @Override
    public SpaceAnnouncementEntity getById(Long id) {
        return spaceAnnouncementMapper.selectById(id);
    }

    @Override
    public void insert(SpaceAnnouncementEntity entity) {
        spaceAnnouncementMapper.insert(entity);
    }

    @Override
    public void updateById(SpaceAnnouncementEntity entity) {
        spaceAnnouncementMapper.updateById(entity);
    }

    @Override
    public SpaceAnnouncementEntity getActiveAnnouncement(Integer category, String spaceId) {
        LambdaQueryWrapper<SpaceAnnouncementEntity> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(SpaceAnnouncementEntity::getStatus, SpaceAnnouncementStatus.ACTIVE.getCode())
               .eq(SpaceAnnouncementEntity::getCategory, category);
        if (AnnouncementCategory.SPACE.getCode() == category) {
            wrapper.eq(SpaceAnnouncementEntity::getSpaceId, spaceId);
        }
        wrapper.orderByDesc(SpaceAnnouncementEntity::getPublishTime)
               .last("LIMIT 1");
        return spaceAnnouncementMapper.selectOne(wrapper);
    }

    @Override
    public List<SpaceAnnouncementEntity> getPendingAnnouncements(Integer category, String spaceId) {
        LambdaQueryWrapper<SpaceAnnouncementEntity> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(SpaceAnnouncementEntity::getStatus, SpaceAnnouncementStatus.PENDING.getCode())
               .eq(SpaceAnnouncementEntity::getCategory, category);
        if (AnnouncementCategory.SPACE.getCode() == category) {
            wrapper.eq(SpaceAnnouncementEntity::getSpaceId, spaceId);
        }
        wrapper.orderByDesc(SpaceAnnouncementEntity::getScheduledPublishTime);
        return spaceAnnouncementMapper.selectList(wrapper);
    }

    @Override
    public List<SpaceAnnouncementEntity> getOfflineAnnouncements(Integer category, String spaceId) {
        LambdaQueryWrapper<SpaceAnnouncementEntity> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(SpaceAnnouncementEntity::getStatus, SpaceAnnouncementStatus.OFFLINE.getCode())
               .eq(SpaceAnnouncementEntity::getCategory, category);
        if (AnnouncementCategory.SPACE.getCode() == category) {
            wrapper.eq(SpaceAnnouncementEntity::getSpaceId, spaceId);
        }
        wrapper.orderByDesc(SpaceAnnouncementEntity::getPublishTime);
        return spaceAnnouncementMapper.selectList(wrapper);
    }

    @Override
    public List<SpaceAnnouncementEntity> getActiveBannerAnnouncements(String spaceId) {
        LambdaQueryWrapper<SpaceAnnouncementEntity> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(SpaceAnnouncementEntity::getStatus, SpaceAnnouncementStatus.ACTIVE.getCode())
               .and(w -> w.eq(SpaceAnnouncementEntity::getCategory, AnnouncementCategory.PLATFORM.getCode())
                          .or(nested -> nested.eq(SpaceAnnouncementEntity::getCategory, AnnouncementCategory.SPACE.getCode())
                                              .eq(SpaceAnnouncementEntity::getSpaceId, spaceId)));
        wrapper.orderByDesc(SpaceAnnouncementEntity::getCategory);
        return spaceAnnouncementMapper.selectList(wrapper);
    }

    @Override
    public List<SpaceAnnouncementEntity> getExpiredActiveAnnouncements() {
        LambdaQueryWrapper<SpaceAnnouncementEntity> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(SpaceAnnouncementEntity::getStatus, SpaceAnnouncementStatus.ACTIVE.getCode())
               .isNotNull(SpaceAnnouncementEntity::getExpireTime)
               .le(SpaceAnnouncementEntity::getExpireTime, LocalDateTime.now());
        return spaceAnnouncementMapper.selectList(wrapper);
    }

    @Override
    public void batchOffline(List<Long> ids) {
        if (ids == null || ids.isEmpty()) return;
        LambdaUpdateWrapper<SpaceAnnouncementEntity> wrapper = new LambdaUpdateWrapper<>();
        wrapper.in(SpaceAnnouncementEntity::getId, ids)
               .set(SpaceAnnouncementEntity::getStatus, SpaceAnnouncementStatus.OFFLINE.getCode())
               .set(SpaceAnnouncementEntity::getOfflineTime, LocalDateTime.now());
        spaceAnnouncementMapper.update(null, wrapper);
    }
}
```

### File 4: src/main/java/com/yottastudios/ns/collabspace/spaceannouncement/manager/impl/SpaceAnnouncementReadRecordManagerImpl.java

```java
package com.yottastudios.ns.collabspace.spaceannouncement.manager.impl;

import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import com.yottastudios.ns.collabspace.spaceannouncement.entity.SpaceAnnouncementReadRecordEntity;
import com.yottastudios.ns.collabspace.spaceannouncement.manager.SpaceAnnouncementReadRecordManager;
import com.yottastudios.ns.collabspace.spaceannouncement.mapper.SpaceAnnouncementReadRecordMapper;
import jakarta.annotation.Resource;
import org.springframework.stereotype.Service;

import java.time.LocalDateTime;
import java.util.Collections;
import java.util.List;

@Service
public class SpaceAnnouncementReadRecordManagerImpl implements SpaceAnnouncementReadRecordManager {

    @Resource
    private SpaceAnnouncementReadRecordMapper readRecordMapper;

    @Override
    public boolean hasRead(Long announcementId, Long userId) {
        LambdaQueryWrapper<SpaceAnnouncementReadRecordEntity> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(SpaceAnnouncementReadRecordEntity::getAnnouncementId, announcementId)
               .eq(SpaceAnnouncementReadRecordEntity::getUserId, userId);
        return readRecordMapper.selectCount(wrapper) > 0;
    }

    @Override
    public void addReadRecord(Long announcementId, Long userId, String spaceId) {
        if (hasRead(announcementId, userId)) return;
        SpaceAnnouncementReadRecordEntity record = SpaceAnnouncementReadRecordEntity.builder()
                .announcementId(announcementId)
                .userId(userId)
                .spaceId(spaceId)
                .createdAt(LocalDateTime.now())
                .build();
        readRecordMapper.insert(record);
    }

    @Override
    public void deleteByAnnouncementId(Long announcementId) {
        LambdaQueryWrapper<SpaceAnnouncementReadRecordEntity> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(SpaceAnnouncementReadRecordEntity::getAnnouncementId, announcementId);
        readRecordMapper.delete(wrapper);
    }

    @Override
    public List<Long> getReadAnnouncementIds(Long userId, List<Long> announcementIds) {
        if (announcementIds == null || announcementIds.isEmpty()) return Collections.emptyList();
        LambdaQueryWrapper<SpaceAnnouncementReadRecordEntity> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(SpaceAnnouncementReadRecordEntity::getUserId, userId)
               .in(SpaceAnnouncementReadRecordEntity::getAnnouncementId, announcementIds)
               .select(SpaceAnnouncementReadRecordEntity::getAnnouncementId);
        return readRecordMapper.selectList(wrapper).stream()
                .map(SpaceAnnouncementReadRecordEntity::getAnnouncementId)
                .toList();
    }
}
```

## Task 8: Modify QueueConfig.java

**File to modify:** src/main/java/com/yottastudios/ns/collabspace/shared/config/QueueConfig.java

Add these 3 constants after the line `public static final String THIRD_APP_UPLOAD_UPDATE_EXCHANGE = "third.app.upload.update.exchange";`:

```java
    // ── Space Announcement 延迟队列 ──
    public static final String SPACE_ANNOUNCEMENT_QUEUE = "space.announcement.delayed.queue";
    public static final String SPACE_ANNOUNCEMENT_KEY = "space.announcement.publish";
    public static final String SPACE_ANNOUNCEMENT_EXCHANGE = "space.announcement.delayed.exchange";
```

Add these 2 beans BEFORE the `bindings()` method:

```java
    @Bean
    public Queue spaceAnnouncementQueue() {
        return QueueBuilder.durable(SPACE_ANNOUNCEMENT_QUEUE).build();
    }

    @Bean
    public CustomExchange spaceAnnouncementExchange() {
        Map<String, Object> args = new HashMap<>();
        args.put("x-delayed-type", "direct");
        return new CustomExchange(SPACE_ANNOUNCEMENT_EXCHANGE, "x-delayed-message", true, false, args);
    }
```

In the `bindings()` method, add a new binding after the `thirdAppUploadUpdateQueue` line. The current bindings() method ends like:
```
                BindingBuilder.bind(thirdAppUploadUpdateQueue()).to(thirdAppUploadUpdateExchange()).with(THIRD_APP_UPLOAD_UPDATE_ROUTING_KEY)
        );
```
Change it to:
```
                BindingBuilder.bind(thirdAppUploadUpdateQueue()).to(thirdAppUploadUpdateExchange()).with(THIRD_APP_UPLOAD_UPDATE_ROUTING_KEY),
                BindingBuilder.bind(spaceAnnouncementQueue()).to(spaceAnnouncementExchange()).with(SPACE_ANNOUNCEMENT_KEY).noargs()
        );
```

