package com.yottastudios.ns.collabspace.spaceannouncement.consumer;

import cn.hutool.json.JSONUtil;
import com.rabbitmq.client.Channel;
import com.yottastudios.ns.collabspace.spaceannouncement.service.ISpaceAnnouncementService;
import com.yottastudios.ns.collabspace.starter.socketio.core.MessageTypeEnum;
import com.yottastudios.ns.collabspace.starter.socketio.core.WebSocketHandler;
import com.yottastudios.ns.collabspace.starter.socketio.core.WebSocketResponseModel;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.amqp.core.Message;
import org.springframework.amqp.rabbit.annotation.RabbitListener;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
import org.springframework.stereotype.Component;

import java.io.IOException;

import static com.yottastudios.ns.collabspace.shared.config.QueueConfig.SPACE_ANNOUNCEMENT_QUEUE;

@Slf4j
@Component
@ConditionalOnProperty(name = "mq.enabled", havingValue = "true", matchIfMissing = true)
public class SpaceAnnouncementConsumer {

    @Resource
    private ISpaceAnnouncementService spaceAnnouncementService;

    @Resource
    private WebSocketHandler webSocketHandler;

    @RabbitListener(queues = SPACE_ANNOUNCEMENT_QUEUE)
    public void handle(Message message, Channel channel) throws IOException {
        String body = new String(message.getBody());
        Long announcementId = Long.parseLong(body);
        log.info("[SpaceAnnouncement] 收到定时发布消息, announcementId={}", announcementId);
        try {
            spaceAnnouncementService.activateScheduledAnnouncement(announcementId);

            // 通知前端刷新
            WebSocketResponseModel wsModel = WebSocketResponseModel.builder()
                    .type(MessageTypeEnum.ADD_ANNOUNCEMENT.getType())
                    .message("空间站公告更新")
                    .status(200)
                    .data(null)
                    .build();
            webSocketHandler.sendAllUserToWebSocketClient(JSONUtil.toJsonStr(wsModel));
        } catch (Exception e) {
            log.error("[SpaceAnnouncement] 定时发布处理失败, announcementId={}", announcementId, e);
        } finally {
            long deliveryTag = message.getMessageProperties().getDeliveryTag();
            channel.basicAck(deliveryTag, false);
        }
    }
}
